import{_ as a,o,c as t,a3 as r}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Module generate:symbol","description":"The generate:symbol module is responsible for planning and rendering documentation pages for individual code symbols. It owns the core data structures SymbolDocPlan and PageDocLayout, which capture the documentation decisions and structural arrangement for a symbol’s page. The module provides public entry points for building page layouts (build_page_doc_layout), iterating over symbol documentation groups (for_each_symbol_doc_group), appending symbol doc pages to the generation pipeline (append_symbol_doc_pages), and querying page capabilities (page_supports_symbol_subpages). It also exposes utilities for title normalization (normalize_frontmatter_title), index path resolution (find_doc_index_path), and inserting cross-reference links and type‑member sections (add_symbol_doc_links, append_type_member_sections). These functions and types form the public API that drives the symbol‑specific page generation process.","frontmatter":{"title":"Module generate:symbol","description":"The generate:symbol module is responsible for planning and rendering documentation pages for individual code symbols. It owns the core data structures SymbolDocPlan and PageDocLayout, which capture the documentation decisions and structural arrangement for a symbol’s page. The module provides public entry points for building page layouts (build_page_doc_layout), iterating over symbol documentation groups (for_each_symbol_doc_group), appending symbol doc pages to the generation pipeline (append_symbol_doc_pages), and querying page capabilities (page_supports_symbol_subpages). It also exposes utilities for title normalization (normalize_frontmatter_title), index path resolution (find_doc_index_path), and inserting cross-reference links and type‑member sections (add_symbol_doc_links, append_type_member_sections). These functions and types form the public API that drives the symbol‑specific page generation process.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/generate/symbol.md","filePath":"en/clore/modules/generate/symbol.md"}'),n={name:"clore/modules/generate/symbol.md"};function i(d,e,c,l,s,p){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="module-generate-symbol" tabindex="-1">Module <code>generate:symbol</code> <a class="header-anchor" href="#module-generate-symbol" aria-label="Permalink to &quot;Module `generate:symbol`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>generate:symbol</code> module is responsible for planning and rendering documentation pages for individual code symbols. It owns the core data structures <code>SymbolDocPlan</code> and <code>PageDocLayout</code>, which capture the documentation decisions and structural arrangement for a symbol’s page. The module provides public entry points for building page layouts (<code>build_page_doc_layout</code>), iterating over symbol documentation groups (<code>for_each_symbol_doc_group</code>), appending symbol doc pages to the generation pipeline (<code>append_symbol_doc_pages</code>), and querying page capabilities (<code>page_supports_symbol_subpages</code>). It also exposes utilities for title normalization (<code>normalize_frontmatter_title</code>), index path resolution (<code>find_doc_index_path</code>), and inserting cross-reference links and type‑member sections (<code>add_symbol_doc_links</code>, <code>append_type_member_sections</code>). These functions and types form the public API that drives the symbol‑specific page generation process.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../config/"><code>config</code></a></li><li><a href="./../extract/"><code>extract</code></a></li><li><a href="./common"><code>generate:common</code></a></li><li><a href="./diagram"><code>generate:diagram</code></a></li><li><a href="./markdown"><code>generate:markdown</code></a></li><li><a href="./model"><code>generate:model</code></a></li><li><code>std</code></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./page"><code>generate:page</code></a></li><li><a href="./scheduler"><code>generate:scheduler</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-generate-pagedoclayout" tabindex="-1"><code>clore::generate::PageDocLayout</code> <a class="header-anchor" href="#clore-generate-pagedoclayout" aria-label="Permalink to &quot;`clore::generate::PageDocLayout`&quot;">​</a></h3><p>Declaration: <code>generate/render/symbol.cppm:19</code></p><p>Definition: <code>generate/render/symbol.cppm:19</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The struct <code>clore::generate::PageDocLayout</code> serves as an internal container that partitions all documentation plans for a single rendered page by symbol category. It holds three separate vectors of <code>SymbolDocPlan</code> — <code>type_docs</code>, <code>variable_docs</code>, and <code>function_docs</code> — each storing the plans for its respective kind of symbol. This separation simplifies the rendering logic by allowing different layout or ordering rules per category while keeping the plans for all symbols of the page collected together. Additionally, the <code>index_paths</code> unordered map associates string keys (typically fully qualified symbol names or link labels) with file-system paths, enabling efficient generation of cross-reference links or an index of pages that contain those symbols. The struct imposes no invariants beyond those implied by the container types: each vector is a simple sequence of plans, and the map must contain no duplicate keys.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li><code>index_paths</code> keys are unique as per <code>std::unordered_map</code></li><li>Each vector may be empty</li><li>Elements in each vector are <code>SymbolDocPlan</code> instances</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>type_docs</code></li><li><code>variable_docs</code></li><li><code>function_docs</code></li><li><code>index_paths</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Populated by documentation generation logic</li><li>Consumed by page rendering code to produce final output</li></ul><h3 id="clore-generate-symboldocplan" tabindex="-1"><code>clore::generate::SymbolDocPlan</code> <a class="header-anchor" href="#clore-generate-symboldocplan" aria-label="Permalink to &quot;`clore::generate::SymbolDocPlan`&quot;">​</a></h3><p>Declaration: <code>generate/render/symbol.cppm:13</code></p><p>Definition: <code>generate/render/symbol.cppm:13</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The struct <code>clore::generate::SymbolDocPlan</code> implements a recursive node in a documentation plan tree. It holds three fields: an owning pointer <code>symbol</code> (to a <code>extract::SymbolInfo</code>, typically pointing into a symbol collection, may be null for the root), a <code>std::string index_path</code> for generating output file paths, and a <code>std::vector&lt;SymbolDocPlan&gt; children</code> that recursively establishes the tree hierarchy. The key invariant is that the tree formed by <code>children</code> mirrors the semantic nesting of the symbols being documented (e.g., namespace → class → member). The <code>symbol</code> pointer is non‑owning; the referenced object must outlive the plan. The <code>index_path</code> is used during rendering to determine file locations, and the recursive structure enables depth‑first traversal without maintaining explicit parent links.</p><h4 id="invariants-1" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-1" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li><code>symbol</code> may be null if no symbol info is associated</li><li><code>children</code> can be empty if the symbol has no sub-symbols</li><li>Each <code>SymbolDocPlan</code> represents a node in a hierarchical documentation plan</li></ul><h4 id="key-members-1" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-1" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>symbol</code></li><li><code>index_path</code></li><li><code>children</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to construct a tree of documentation plans for symbols and their nested children</li><li>Likely processed by a renderer to generate documentation output</li></ul><h2 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h2><h3 id="clore-generate-add-symbol-doc-links" tabindex="-1"><code>clore::generate::add_symbol_doc_links</code> <a class="header-anchor" href="#clore-generate-add-symbol-doc-links" aria-label="Permalink to &quot;`clore::generate::add_symbol_doc_links`&quot;">​</a></h3><p>Declaration: <code>generate/render/symbol.cppm:43</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>This variable is consumed by <code>clore::generate::(anonymous namespace)::render_symbol_page</code> to add documentation links to rendered symbol pages. It likely holds a callable or function reference that performs the link insertion.</p><h4 id="mutation" tabindex="-1">Mutation <a class="header-anchor" href="#mutation" aria-label="Permalink to &quot;Mutation&quot;">​</a></h4><p>No mutation is evident from the extracted code.</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called by <code>render_symbol_page</code></li></ul><h3 id="clore-generate-append-symbol-doc-pages" tabindex="-1"><code>clore::generate::append_symbol_doc_pages</code> <a class="header-anchor" href="#clore-generate-append-symbol-doc-pages" aria-label="Permalink to &quot;`clore::generate::append_symbol_doc_pages`&quot;">​</a></h3><p>Declaration: <code>generate/render/symbol.cppm:60</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>Based on its name, <code>append_symbol_doc_pages</code> is likely used to append documentation pages for symbols during generation. No evidence of its specific role or consumption is provided.</p><h4 id="mutation-1" tabindex="-1">Mutation <a class="header-anchor" href="#mutation-1" aria-label="Permalink to &quot;Mutation&quot;">​</a></h4><p>No mutation is evident from the extracted code.</p><h3 id="clore-generate-append-type-member-sections" tabindex="-1"><code>clore::generate::append_type_member_sections</code> <a class="header-anchor" href="#clore-generate-append-type-member-sections" aria-label="Permalink to &quot;`clore::generate::append_type_member_sections`&quot;">​</a></h3><p>Declaration: <code>generate/render/symbol.cppm:49</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The variable&#39;s role is not explicitly shown in the evidence; it appears only in a declaration snippet. It is probably a callable (e.g., a function pointer or lambda) that participates in rendering type member documentation sections, but no further usage or mutation is observable from the provided context.</p><h4 id="mutation-2" tabindex="-1">Mutation <a class="header-anchor" href="#mutation-2" aria-label="Permalink to &quot;Mutation&quot;">​</a></h4><p>No mutation is evident from the extracted code.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-generate-build-page-doc-layout" tabindex="-1"><code>clore::generate::build_page_doc_layout</code> <a class="header-anchor" href="#clore-generate-build-page-doc-layout" aria-label="Permalink to &quot;`clore::generate::build_page_doc_layout`&quot;">​</a></h3><p>Declaration: <code>generate/render/symbol.cppm:37</code></p><p>Definition: <code>generate/render/symbol.cppm:897</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function first performs early‑exit checks: if <code>page_supports_symbol_subpages</code> returns false, or the base directory derived via <code>page_directory_of</code> is empty, it returns an empty <code>PageDocLayout</code>. Otherwise it collects all relevant symbols for the page—using <code>collect_namespace_symbols</code> for namespace pages and <code>collect_implementation_symbols</code> otherwise—and classifies them into three vectors based on kind predicates (<code>is_type_kind</code>, <code>is_variable_kind</code>, <code>is_function_kind</code>). Each category is then processed by <code>build_symbol_doc_plans</code> to populate the corresponding field of the layout: <code>type_docs</code>, <code>variable_docs</code>, and <code>function_docs</code>. Finally <code>for_each_symbol_doc_group</code> iterates over every group of plans and calls <code>register_symbol_doc_plan</code> to integrate them into the layout, which is then returned.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Modifies the returned <code>PageDocLayout</code> object by populating its <code>type_docs</code>, <code>variable_docs</code>, <code>function_docs</code> members and registering symbol doc plans via <code>register_symbol_doc_plan</code></li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>plan (<code>PagePlan</code>)</li><li>model (<code>ProjectModel</code>)</li><li><code>page_supports_symbol_subpages</code></li><li><code>page_directory_of</code></li><li><code>collect_namespace_symbols</code></li><li><code>collect_implementation_symbols</code></li><li><code>is_type_kind</code></li><li><code>is_variable_kind</code></li><li><code>is_function_kind</code></li><li><code>build_symbol_doc_plans</code></li><li><code>for_each_symbol_doc_group</code></li><li><code>register_symbol_doc_plan</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Returned <code>PageDocLayout</code> object (fields: <code>type_docs</code>, <code>variable_docs</code>, <code>function_docs</code>)</li><li>(via <code>register_symbol_doc_plan</code>) internal mapping within layout</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called during page documentation generation to construct a layout of symbol documentation plans categorized by kind</li></ul><h3 id="clore-generate-find-doc-index-path" tabindex="-1"><code>clore::generate::find_doc_index_path</code> <a class="header-anchor" href="#clore-generate-find-doc-index-path" aria-label="Permalink to &quot;`clore::generate::find_doc_index_path`&quot;">​</a></h3><p>Declaration: <code>generate/render/symbol.cppm:40</code></p><p>Definition: <code>generate/render/symbol.cppm:804</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function performs a direct map lookup on <code>layout.index_paths</code>, constructing a temporary <code>std::string</code> from the <code>qualified_name</code> view to serve as the key. If the entry exists, it returns a pointer to the associated value without copying; otherwise it returns <code>nullptr</code>. This avoids unnecessary string duplication and provides a simple existence-check mechanism for the precomputed index paths. The implementation has no external dependencies beyond the <code>PageDocLayout</code> data structure and the standard library.</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>layout<code>.index_paths</code></li><li><code>qualified_name</code></li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>lookup index path by qualified name</li><li>used during page generation to resolve symbol paths</li></ul><h3 id="clore-generate-for-each-symbol-doc-group" tabindex="-1"><code>clore::generate::for_each_symbol_doc_group</code> <a class="header-anchor" href="#clore-generate-for-each-symbol-doc-group" aria-label="Permalink to &quot;`clore::generate::for_each_symbol_doc_group`&quot;">​</a></h3><p>Declaration: <code>generate/render/symbol.cppm:27</code></p><p>Definition: <code>generate/render/symbol.cppm:27</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function <code>clore::generate::for_each_symbol_doc_group</code> implements a simple dispatch loop over the three documentation group containers stored in a <code>PageDocLayout</code>. It sequentially invokes the <code>Visitor</code> functor on <code>layout.type_docs</code>, <code>layout.variable_docs</code>, and <code>layout.function_docs</code>, in that fixed order. There is no branching or conditional logic; the control flow is strictly linear. The design relies on <code>PageDocLayout</code> exposing these three public fields as the canonical partitions of symbol documentation. The visitor is forwarded via a forwarding reference, allowing both lvalue and rvalue callables. No internal state is modified, and no return value is extracted beyond the void return type. The function serves as a central iterator for downstream processing of all symbol documentation groups within a layout.</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>layout.type_docs</code></li><li><code>layout.variable_docs</code></li><li><code>layout.function_docs</code></li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Iterating over all symbol doc groups in a page layout</li><li>Applying a visitor to each group for rendering or analysis</li></ul><h3 id="clore-generate-normalize-frontmatter-title" tabindex="-1"><code>clore::generate::normalize_frontmatter_title</code> <a class="header-anchor" href="#clore-generate-normalize-frontmatter-title" aria-label="Permalink to &quot;`clore::generate::normalize_frontmatter_title`&quot;">​</a></h3><p>Declaration: <code>generate/render/symbol.cppm:33</code></p><p>Definition: <code>generate/render/symbol.cppm:885</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function first strips inline Markdown formatting from the input <code>page_title</code> via <code>strip_inline_markdown</code>. If the resulting plain text is non‑empty, it is returned directly. Otherwise, the function falls back to <code>trim_ascii</code> applied to the original <code>page_title</code>, which removes leading and trailing ASCII whitespace. This fallback ensures that a title consisting entirely of Markdown markup still yields a non‑empty result.</p><p>The implementation depends on two internal helper functions: <code>strip_inline_markdown</code> for removing lightweight formatting (e.g., bold, italic, inline code) from the title string, and <code>trim_ascii</code> for whitespace trimming. Both are presumed to be defined in the same translation unit or namespace. No external dependencies or complex control flow are involved; the logic is a straightforward conditional return based on the intermediate plain‑text result.</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>page_title</code> parameter</li></ul><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to normalize frontmatter titles before page rendering</li><li>Called during documentation generation to clean titles</li></ul><h3 id="clore-generate-page-supports-symbol-subpages" tabindex="-1"><code>clore::generate::page_supports_symbol_subpages</code> <a class="header-anchor" href="#clore-generate-page-supports-symbol-subpages" aria-label="Permalink to &quot;`clore::generate::page_supports_symbol_subpages`&quot;">​</a></h3><p>Declaration: <code>generate/render/symbol.cppm:35</code></p><p>Definition: <code>generate/render/symbol.cppm:893</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function evaluates a single condition: it accesses the <code>page_type</code> field of the provided <code>PagePlan</code> object and returns <code>true</code> if that value equals either <code>PageType::Namespace</code> or <code>PageType::Module</code>; otherwise it returns <code>false</code>. The control flow is a direct equality check with no branching or external calls. The implementation depends only on the <code>PagePlan</code> type and the <code>PageType</code> enumeration; no other analysis or state is consulted.</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>plan.page_type</code></li></ul><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used in page generation to decide if subpages should be created for a given page plan.</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>The <code>generate:symbol</code> module is responsible for planning and rendering individual symbol documentation pages. It imports support from <code>generate:common</code> (linking and Markdown utilities), <code>generate:markdown</code> (document AST construction), <code>generate:model</code> (page plans and symbol analyses), <code>config</code>, <code>extract</code>, <code>generate:diagram</code>, and the standard library. Internally, the module is decomposed into a public interface—comprising <code>SymbolDocPlan</code>, <code>PageDocLayout</code>, and functions such as <code>build_page_doc_layout</code>, <code>for_each_symbol_doc_group</code>, and <code>append_symbol_doc_pages</code>—and an anonymous-namespace implementation layer that handles plan construction (<code>build_symbol_doc_plans</code>, <code>collect_documentable_children</code>, <code>collect_member_symbols</code>), Markdown rendering (<code>render_symbol_page</code>, <code>render_document_page</code>, <code>declaration_snippet</code>, <code>implementation_snippet</code>), and structural helpers (<code>sanitize_doc_slug</code>, <code>join_relative_paths</code>, <code>normalize_frontmatter_title</code>). This layering separates the stable export contract from the internal rendering and planning logic, enabling the pipeline to evolve without affecting external callers.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../config/">Module config</a></li><li><a href="./../extract/">Module extract</a></li><li><a href="./common">Module generate:common</a></li><li><a href="./diagram">Module generate:diagram</a></li><li><a href="./markdown">Module generate:markdown</a></li><li><a href="./model">Module generate:model</a></li></ul>',114)])])}const h=a(n,[["render",i]]);export{u as __pageData,h as default};
